features.snippet:
class source_driver;
    virtual stream_if vif;
    function new(virtual stream_if vif);
        this.vif = vif;
    endfunction
endclass

stream_if a (.clk(clk));
stream_if b (.clk(clk));
source_driver src;
sink_driver snk;
initial begin
    src = new(a);
    snk = new(b);
end

interface stream_if (input logic clk);
    logic valid, ready;
    logic [7:0] data;
    clocking cb @(posedge clk);
        default input #1step output #0;
        output valid, data;
        input ready;
    endclocking
endinterface

always_ff @(posedge clk) begin
    if (s_ready) begin
        m_valid <= s_valid;
        m_data <= s_data;
    end
end
assign s_ready = !m_valid || m_ready;

task run();
    vif.cb.valid <= 1'b0;
    vif.cb.data <= '0;
    @(vif.cb);
    vif.cb.valid <= 1'b1;
    vif.cb.data <= 8'hAB;
endtask
